/* Pricing Card */
.pricing-card {
  background: var(--card-bg, #ffffff);
  border-radius: var(--card-radius, 20px);
  padding: var(--card-padding, 32px);
  border: 1px solid var(--card-border, #e2e8f0);
  box-shadow: var(--card-shadow, 0 4px 16px rgba(0,0,0,0.07));
  display: flex;
  flex-direction: column;
  gap: 24px;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  position: relative;
  overflow: hidden;
}
.pricing-card:hover {
  transform: translateY(-6px);
  box-shadow: 0 20px 48px rgba(0,0,0,0.14);
}

/* Featured Card */
.pricing-card.featured {
  background: linear-gradient(155deg, #7c3aed 0%, #4f46e5 100%);
  border-color: transparent;
  box-shadow: 0 8px 32px rgba(124,58,237,0.35);
  color: #fff;
}
.pricing-card.featured::before {
  content: 'Most Popular';
  position: absolute;
  top: 16px;
  right: -28px;
  background: #f59e0b;
  color: #fff;
  font-size: 11px;
  font-weight: 700;
  padding: 4px 36px;
  transform: rotate(45deg);
  letter-spacing: 0.5px;
}
[dir="rtl"] .pricing-card.featured::before { right: auto; left: -28px; transform: rotate(-45deg); }

/* Pricing Top */
.pricing-top { text-align: center; }
.pricing-plan {
  font-size: var(--title-font-size, 20px);
  font-weight: var(--title-font-weight, 700);
  color: var(--title-color, #0f172a);
  margin: 0 0 6px;
}
.pricing-card.featured .pricing-plan { color: #fff; }
.pricing-tagline {
  font-size: var(--subtitle-font-size, 13px);
  color: var(--subtitle-color, #64748b);
  margin: 0 0 20px;
}
.pricing-card.featured .pricing-tagline { color: rgba(255,255,255,0.75); }
.pricing-price-wrap {
  display: flex;
  align-items: flex-end;
  justify-content: center;
  gap: 4px;
}
.pricing-price {
  font-size: var(--price-font-size, 40px);
  font-weight: var(--price-font-weight, 800);
  color: var(--price-color, #0f172a);
  line-height: 1;
  letter-spacing: -1px;
}
.pricing-card.featured .pricing-price { color: #fff; }
.pricing-period {
  font-size: 14px;
  color: #94a3b8;
  padding-bottom: 6px;
}
.pricing-card.featured .pricing-period { color: rgba(255,255,255,0.65); }

/* Features List */
.pricing-features {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 10px;
  flex: 1;
}
.pricing-feature {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  font-size: var(--description-font-size, 14px);
  color: var(--description-color, #475569);
  line-height: 1.5;
}
.pricing-feature::before {
  content: '✓';
  color: #10b981;
  font-weight: 700;
  font-size: 14px;
  flex-shrink: 0;
  margin-top: 1px;
}
.pricing-feature.muted { opacity: 0.4; }
.pricing-feature.muted::before { content: '✗'; color: #94a3b8; }
.pricing-card.featured .pricing-feature { color: rgba(255,255,255,0.9); }
.pricing-card.featured .pricing-feature::before { color: #86efac; }

/* CTA Button */
.pricing-btn {
  display: block;
  text-align: center;
  padding: 14px 24px;
  border-radius: 50px;
  background: #7c3aed;
  color: #fff;
  font-size: var(--button-font-size, 15px);
  font-weight: var(--button-font-weight, 700);
  text-decoration: none;
  transition: all 0.25s;
  box-shadow: 0 4px 12px rgba(124,58,237,0.25);
}
.pricing-btn:hover {
  background: #6d28d9;
  transform: translateY(-1px);
  box-shadow: 0 8px 20px rgba(124,58,237,0.35);
}
.pricing-card.featured .pricing-btn {
  background: #fff;
  color: #7c3aed;
}
.pricing-card.featured .pricing-btn:hover {
  background: #f3f4f6;
}

/* Note */
.pricing-note {
  font-size: 12px;
  color: #94a3b8;
  text-align: center;
  margin: 0;
}
.pricing-card.featured .pricing-note { color: rgba(255,255,255,0.55); }

/* Dark Mode */
.dark .pricing-card:not(.featured), [data-theme="dark"] .pricing-card:not(.featured) {
  background: #1e293b;
  border-color: #334155;
}
.dark .pricing-plan, [data-theme="dark"] .pricing-plan { color: #f1f5f9; }
.dark .pricing-price, [data-theme="dark"] .pricing-price { color: #e2e8f0; }
.dark .pricing-feature, [data-theme="dark"] .pricing-feature { color: #94a3b8; }

/* RTL */
[dir="rtl"] .pricing-feature { flex-direction: row-reverse; text-align: right; }
